import React, {  useEffect, useState } from "react";
import {useLocation, useNavigate} from "react-router-dom";
import './Logout.css';
import './Welcome';
import axios from "axios";
function Logout () {
    const [responses, setResponse] = useState([]);
    const [deleteResponse, setDeleteResponse] = useState([]);
    useEffect((userName) => {
        axios.get(`http://localhost:8080/user/${userName}/items`).then(response => setResponse(response.data))
        .catch(error => {console.log("An error happened:" + error)})
    }, []);
    const navigate = useNavigate();
    const location = useLocation();
//     useEffect((userName, id) => {
//         axios.delete(`http://localhost:8080/users/${userName}/items/${id}`).then(response => console.log(response.id, response.userName))
//        .catch(error => {console.log("An error happened:" + error)})
//    }, []);
   const deleteRequest = (userName, id) => {
        axios.delete(`http://localhost:8080/users/${userName}/items/${id}`).then(response => setDeleteResponse(response.data))
       .catch(error => {console.log(error.data)})
        console.log(deleteResponse)
        return deleteResponse;
   }
    return (
        <div className="list-of-itmes">
        <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.3.0/css/all.min.css"/>
        <div className="nav-bar">
        <div className="header">
        <a href="/" onClick={() => navigate('/')}className="logo">Productiv</a>
        <div className="header-right">
       {/* Create loader! */}
        <a href="Welcome" onClick={() => navigate('Welcome')}>My Account</a>
        <a href="/" onClick={() => navigate('/')}>Logout</a>
        </div>
        </div>
            <h1>Welcome {location.state.userName}!</h1>
        </div>
            <table>
                <td>
                {
                 responses.map(response => (<tr><button onClick={() => deleteRequest(response.userName, response.id)}>Delete</button><tr>I.D {response.id}</tr><tr>{response.userName}</tr><tr>{response.targetDate}</tr>{response.done}</tr>))
                }
                </td>
            </table>
        </div>
    )
}

export default Logout;
